t.script:
(function(){
    var l='ar';
    try{ var s=localStorage.getItem('df_lang'); if(s==='en'||s==='ar') l=s; }catch(e){}
    var w=document.getElementById('df-perfume-wrap');
    if(w){ w.setAttribute('dir',l==='ar'?'rtl':'ltr'); w.classList.add('lang-'+l); }
    else{
        document.addEventListener('DOMContentLoaded',function(){
            var w2=document.getElementById('df-perfume-wrap');
            if(w2){ w2.setAttribute('dir',l==='ar'?'rtl':'ltr'); w2.classList.add('lang-'+l); }
        });
    }
})();

